import{_ as n,o as t,c as r,ag as a}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"PDF-Anpassung","description":"","frontmatter":{},"headers":[],"relativePath":"de/settings/pdf.md","filePath":"de/settings/pdf.md"}'),i={name:"de/settings/pdf.md"};function s(o,e,l,u,h,d){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="pdf-anpassung" tabindex="-1">PDF-Anpassung <a class="header-anchor" href="#pdf-anpassung" aria-label="Permalink to &quot;PDF-Anpassung&quot;">​</a></h1><p>Passen Sie das Erscheinungsbild Ihrer Rechnungs-, Angebots- und Gutschrift-PDFs an Ihre Marke an.</p><h2 id="pdf-editor" tabindex="-1">PDF-Editor <a class="header-anchor" href="#pdf-editor" aria-label="Permalink to &quot;PDF-Editor&quot;">​</a></h2><p>Der visuelle PDF-Editor ermöglicht es Ihnen, Ihr Dokumentlayout mit einer Live-Vorschau anzupassen.</p><h3 id="editor-aufrufen" tabindex="-1">Editor aufrufen <a class="header-anchor" href="#editor-aufrufen" aria-label="Permalink to &quot;Editor aufrufen&quot;">​</a></h3><p>Gehen Sie zu <strong>Unternehmen &gt; PDF-Editor</strong> oder rufen Sie ihn über Unternehmen &gt; Branding auf.</p><h3 id="anpassungsoptionen" tabindex="-1">Anpassungsoptionen <a class="header-anchor" href="#anpassungsoptionen" aria-label="Permalink to &quot;Anpassungsoptionen&quot;">​</a></h3><h4 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h4><ul><li><strong>Logo-Position und -Größe</strong> — Platzieren Sie Ihr Logo dort, wo es am besten aussieht</li><li><strong>Firmeninformationen-Platzierung</strong> — Positionieren Sie Ihre Geschäftsdaten</li><li><strong>Kundeninformationen-Platzierung</strong> — Wo Kundendetails erscheinen</li><li><strong>Positionstabelle</strong> — Spaltenbreiten und Ausrichtung</li></ul><h4 id="inhalt" tabindex="-1">Inhalt <a class="header-anchor" href="#inhalt" aria-label="Permalink to &quot;Inhalt&quot;">​</a></h4><p>Wählen Sie, welche Felder angezeigt oder ausgeblendet werden:</p><ul><li>USt.-Nummer des Unternehmens</li><li>Handelsregisternummer</li><li>IBAN / Bankdaten</li><li>Zahlungsbedingungen</li><li>Anmerkungsbereich</li><li>Fußzeilentext</li></ul><h4 id="gestaltung" tabindex="-1">Gestaltung <a class="header-anchor" href="#gestaltung" aria-label="Permalink to &quot;Gestaltung&quot;">​</a></h4><ul><li><strong>Schriftart</strong> — Aus verfügbaren Schriftarten wählen</li><li><strong>Schriftgröße</strong> — Textgröße anpassen</li><li><strong>Akzentfarbe</strong> — Ihre Markenfarbe für Überschriften und Akzente</li><li><strong>Zeilenabstand</strong> — Dokumentdichte anpassen</li></ul><h3 id="vorschau" tabindex="-1">Vorschau <a class="header-anchor" href="#vorschau" aria-label="Permalink to &quot;Vorschau&quot;">​</a></h3><p>Der Editor zeigt eine Echtzeit-Vorschau mit Beispieldaten. Sie können auch ein <strong>Muster-PDF</strong> generieren, um genau zu sehen, wie eine gedruckte Rechnung aussehen wird.</p><h2 id="dokumenttypen" tabindex="-1">Dokumenttypen <a class="header-anchor" href="#dokumenttypen" aria-label="Permalink to &quot;Dokumenttypen&quot;">​</a></h2><p>PDF-Einstellungen gelten für alle generierten Dokumente:</p><ul><li><strong>Rechnungen</strong> — Standard-Abrechnungsdokumente</li><li><strong>Angebote</strong> — Angebotsdokumente</li><li><strong>Gutschriften</strong> — Erstattungs-/Korrekturdokumente</li><li><strong>Erinnerungen</strong> — Zahlungserinnerungsdokumente</li></ul><h2 id="sprachunterstutzung" tabindex="-1">Sprachunterstützung <a class="header-anchor" href="#sprachunterstutzung" aria-label="Permalink to &quot;Sprachunterstützung&quot;">​</a></h2><p>PDFs werden in der Sprache der Rechnung generiert. Wenn Sie eine Rechnung auf Deutsch versenden, erscheinen die PDF-Bezeichnungen (wie „Rechnung&quot;, „Fälligkeitsdatum&quot;, „Gesamt&quot;) auf Deutsch.</p><p>Unterstützte PDF-Sprachen: Englisch, Niederländisch, Deutsch, Französisch.</p><h2 id="logo-anforderungen" tabindex="-1">Logo-Anforderungen <a class="header-anchor" href="#logo-anforderungen" aria-label="Permalink to &quot;Logo-Anforderungen&quot;">​</a></h2><p>Für beste Ergebnisse:</p><ul><li><strong>Format:</strong> PNG mit transparentem Hintergrund (empfohlen), JPG oder SVG</li><li><strong>Auflösung:</strong> Mindestens 300px Breite</li><li><strong>Seitenverhältnis:</strong> Querformat- oder quadratische Logos funktionieren am besten</li><li><strong>Dateigröße:</strong> Unter 2MB</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>SVG-Logos werden für E-Mail-Kompatibilität automatisch in PNG konvertiert.</p></div><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Generieren Sie nach Änderungen ein Muster-PDF, um das Layout zu überprüfen</li><li>Verwenden Sie die Akzentfarbe Ihrer Marke für ein professionelles Erscheinungsbild</li><li>Halten Sie das Layout übersichtlich — überladen Sie das PDF nicht mit zu vielen Informationen</li><li>Testen Sie mit einer echten Rechnung (an sich selbst), bevor Sie an Kunden versenden</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Erweiterte PDF-Anpassung erfordert den <strong>Pro</strong>-Tarif oder höher.</p></div>',29)])])}const p=n(i,[["render",s]]);export{c as __pageData,p as default};
